"use client";

import { useEffect, useMemo, useRef, useState } from "react";

type PersonType = "adquirente" | "transmitente";

type PersonRecord = {
  id: string;
  type: PersonType;
  nome: string;
  cpfCnpj: string;
  endereco: string;
  numero: string;
  complemento: string;
  bairro: string;
  cidade: string;
  uf: string;
  cep: string;
};

type PropertyRecord = {
  id: string;
  nome: string;
  endereco: string;
  numero: string;
  bairro: string;
  cidade: string;
  uf: string;
  imovelCep: string;
  complemento: string;
  matricula: string;
  ficha: string;
  livro: string;
  descricaoImovel: string;
  areaTotal: string;
  areaConstruida: string;
  unidadeArea: string;
};

type SavedDocument = {
  id: string;
  createdAt: string;
  locked: boolean;
  form: FormData;
};

type SelectorItem = {
  id: string;
  nome: string;
  cpfCnpj?: string;
};

type FormData = {
  numeroItbi: string;
  ano: string;
  dataEmissao: string;

  adquirenteNome: string;
  adquirenteCpfCnpj: string;
  adquirenteEndereco: string;
  adquirenteNumero: string;
  adquirenteComplemento: string;
  adquirenteBairro: string;
  adquirenteCidade: string;
  adquirenteUf: string;
  adquirenteCep: string;

  transmitenteNome: string;
  transmitenteCpfCnpj: string;
  transmitenteEndereco: string;
  transmitenteNumero: string;
  transmitenteComplemento: string;
  transmitenteBairro: string;
  transmitenteCidade: string;
  transmitenteUf: string;
  transmitenteCep: string;

  tipoTransmissao: string;
  aliquota: string;
  valorVenal: string;
  valorFinanciado: string;

  imovelEndereco: string;
  imovelNumero: string;
  imovelBairro: string;
  imovelCidade: string;
  imovelUf: string;
  imovelCep: string;
  imovelComplemento: string;

  matricula: string;
  ficha: string;
  livro: string;
  descricaoImovel: string;
  areaTotal: string;
  areaConstruida: string;
  unidadeArea: string;

  observacoes: string;
  responsavelNome: string;
  responsavelCargo: string;
  responsavelPortaria: string;
};

const STORAGE_KEYS = {
  draft: "itbi:draft:v7",
  people: "itbi:people:v7",
  properties: "itbi:properties:v7",
  documents: "itbi:documents:v7",
};

const MUNICIPAL_FLAG_SRC = "data:image/png;base64,";

const CITY_SYMBOL_SRC = "data:image/png;base64,";

function createEmptyForm(): FormData {
  return {
    numeroItbi: "",
    ano: new Date().getFullYear().toString(),
    dataEmissao: new Date().toISOString().slice(0, 10),

    adquirenteNome: "",
    adquirenteCpfCnpj: "",
    adquirenteEndereco: "",
    adquirenteNumero: "",
    adquirenteComplemento: "",
    adquirenteBairro: "",
    adquirenteCidade: "Eldorado do Carajás",
    adquirenteUf: "PA",
    adquirenteCep: "",

    transmitenteNome: "",
    transmitenteCpfCnpj: "",
    transmitenteEndereco: "",
    transmitenteNumero: "",
    transmitenteComplemento: "",
    transmitenteBairro: "",
    transmitenteCidade: "Eldorado do Carajás",
    transmitenteUf: "PA",
    transmitenteCep: "",

    tipoTransmissao: "Compra e Venda",
    aliquota: "2",
    valorVenal: "",
    valorFinanciado: "0",

    imovelEndereco: "",
    imovelNumero: "",
    imovelBairro: "",
    imovelCidade: "Eldorado do Carajás",
    imovelUf: "PA",
    imovelCep: "",
    imovelComplemento: "",

    matricula: "",
    ficha: "",
    livro: "",
    descricaoImovel: "",
    areaTotal: "",
    areaConstruida: "",
    unidadeArea: "hectares",

    observacoes: "",
    responsavelNome: "Wigo de Sousa Almeida",
    responsavelCargo: "Coordenador de Arrecadação Fazendária",
    responsavelPortaria: "Port. Nº 130/2025-GPM",
  };
}

function currencyToNumber(value: string) {
  const clean = value.replace(/\./g, "").replace(",", ".").replace(/[^\d.]/g, "");
  return Number(clean) || 0;
}

function numberToCurrencyInput(value: number) {
  return new Intl.NumberFormat("pt-BR", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(value);
}

function formatCurrency(value: number) {
  return new Intl.NumberFormat("pt-BR", {
    style: "currency",
    currency: "BRL",
  }).format(value);
}

function uid() {
  return `${Date.now()}-${Math.random().toString(16).slice(2)}`;
}

export default function NovoItbiPage() {
  const [form, setForm] = useState<FormData>(createEmptyForm());
  const [people, setPeople] = useState<PersonRecord[]>([]);
  const [properties, setProperties] = useState<PropertyRecord[]>([]);
  const [documents, setDocuments] = useState<SavedDocument[]>([]);
  const [notice, setNotice] = useState("");
  const importInputRef = useRef<HTMLInputElement | null>(null);

  useEffect(() => {
    loadAll();
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.draft, JSON.stringify(form));
  }, [form]);

  useEffect(() => {
    if (!notice) return;
    const timer = setTimeout(() => setNotice(""), 3500);
    return () => clearTimeout(timer);
  }, [notice]);

  const valores = useMemo(() => {
    const valorVenal = currencyToNumber(form.valorVenal);
    const valorFinanciado = currencyToNumber(form.valorFinanciado);
    const aliquota = Number(form.aliquota.replace(",", ".")) || 0;
    const baseCalculo = valorVenal;
    const imposto = baseCalculo * (aliquota / 100);
    const total = imposto;
    return { valorVenal, valorFinanciado, aliquota, baseCalculo, imposto, total };
  }, [form]);

  const essentialStatus = useMemo(() => {
    const items = [
      ["Nº do ITBI", form.numeroItbi],
      ["Adquirente", form.adquirenteNome],
      ["Transmitente", form.transmitenteNome],
      ["Descrição do imóvel", form.descricaoImovel],
      ["Valor venal", form.valorVenal],
    ];
    const filled = items.filter((item) => String(item[1]).trim()).length;
    return { filled, total: items.length, items };
  }, [form]);

  function loadAll() {
    try {
      const draft = localStorage.getItem(STORAGE_KEYS.draft);
      const storedPeople = localStorage.getItem(STORAGE_KEYS.people);
      const storedProperties = localStorage.getItem(STORAGE_KEYS.properties);
      const storedDocuments = localStorage.getItem(STORAGE_KEYS.documents);
      if (draft) setForm({ ...createEmptyForm(), ...JSON.parse(draft) });
      if (storedPeople) setPeople(JSON.parse(storedPeople));
      if (storedProperties) setProperties(JSON.parse(storedProperties));
      if (storedDocuments) setDocuments(JSON.parse(storedDocuments));
    } catch {
      setNotice("Não foi possível carregar alguns dados locais.");
    }
  }

  function persistPeople(next: PersonRecord[]) {
    setPeople(next);
    localStorage.setItem(STORAGE_KEYS.people, JSON.stringify(next));
  }

  function persistProperties(next: PropertyRecord[]) {
    setProperties(next);
    localStorage.setItem(STORAGE_KEYS.properties, JSON.stringify(next));
  }

  function persistDocuments(next: SavedDocument[]) {
    setDocuments(next);
    localStorage.setItem(STORAGE_KEYS.documents, JSON.stringify(next));
  }

  function updateField(field: keyof FormData, value: string) {
    setForm((current) => ({ ...current, [field]: value }));
  }

  function formatMoneyField(field: keyof FormData) {
    const value = currencyToNumber(String(form[field]));
    updateField(field, numberToCurrencyInput(value));
  }

  function saveCurrentPerson(type: PersonType) {
    const data = type === "adquirente"
      ? {
          nome: form.adquirenteNome,
          cpfCnpj: form.adquirenteCpfCnpj,
          endereco: form.adquirenteEndereco,
          numero: form.adquirenteNumero,
          complemento: form.adquirenteComplemento,
          bairro: form.adquirenteBairro,
          cidade: form.adquirenteCidade,
          uf: form.adquirenteUf,
          cep: form.adquirenteCep,
        }
      : {
          nome: form.transmitenteNome,
          cpfCnpj: form.transmitenteCpfCnpj,
          endereco: form.transmitenteEndereco,
          numero: form.transmitenteNumero,
          complemento: form.transmitenteComplemento,
          bairro: form.transmitenteBairro,
          cidade: form.transmitenteCidade,
          uf: form.transmitenteUf,
          cep: form.transmitenteCep,
        };

    if (!data.nome.trim() && !data.cpfCnpj.trim()) {
      setNotice("Preencha pelo menos nome ou CPF/CNPJ antes de salvar.");
      return;
    }

    const existingIndex = people.findIndex((person) => person.type === type && person.cpfCnpj && person.cpfCnpj === data.cpfCnpj);
    const record: PersonRecord = { id: existingIndex >= 0 ? people[existingIndex].id : uid(), type, ...data };
    const next = existingIndex >= 0 ? people.map((p, i) => (i === existingIndex ? record : p)) : [record, ...people];
    persistPeople(next);
    setNotice(type === "adquirente" ? "Adquirente salvo." : "Transmitente salvo.");
  }

  function applyPerson(id: string, type: PersonType) {
    const person = people.find((p) => p.id === id);
    if (!person) return;
    setForm((current) => type === "adquirente"
      ? {
          ...current,
          adquirenteNome: person.nome,
          adquirenteCpfCnpj: person.cpfCnpj,
          adquirenteEndereco: person.endereco,
          adquirenteNumero: person.numero || "",
          adquirenteComplemento: person.complemento || "",
          adquirenteBairro: person.bairro || "",
          adquirenteCidade: person.cidade || "Eldorado do Carajás",
          adquirenteUf: person.uf || "PA",
          adquirenteCep: person.cep,
        }
      : {
          ...current,
          transmitenteNome: person.nome,
          transmitenteCpfCnpj: person.cpfCnpj,
          transmitenteEndereco: person.endereco,
          transmitenteNumero: person.numero || "",
          transmitenteComplemento: person.complemento || "",
          transmitenteBairro: person.bairro || "",
          transmitenteCidade: person.cidade || "Eldorado do Carajás",
          transmitenteUf: person.uf || "PA",
          transmitenteCep: person.cep,
        }
    );
  }

  function removePerson(id: string) {
    persistPeople(people.filter((person) => person.id !== id));
    setNotice("Cadastro removido.");
  }

  function saveCurrentProperty() {
    if (!form.descricaoImovel.trim() && !form.matricula.trim()) {
      setNotice("Preencha descrição ou matrícula antes de salvar o imóvel.");
      return;
    }
    const nome = form.matricula ? `Matrícula ${form.matricula}` : form.descricaoImovel.slice(0, 60);
    const existingIndex = properties.findIndex((property) => property.matricula && property.matricula === form.matricula);
    const record: PropertyRecord = {
      id: existingIndex >= 0 ? properties[existingIndex].id : uid(),
      nome,
      endereco: form.imovelEndereco,
      numero: form.imovelNumero,
      bairro: form.imovelBairro,
      cidade: form.imovelCidade,
      uf: form.imovelUf,
      imovelCep: form.imovelCep,
      complemento: form.imovelComplemento,
      matricula: form.matricula,
      ficha: form.ficha,
      livro: form.livro,
      descricaoImovel: form.descricaoImovel,
      areaTotal: form.areaTotal,
      areaConstruida: form.areaConstruida,
      unidadeArea: form.unidadeArea,
    };
    const next = existingIndex >= 0 ? properties.map((p, i) => (i === existingIndex ? record : p)) : [record, ...properties];
    persistProperties(next);
    setNotice("Imóvel salvo.");
  }

  function applyProperty(id: string) {
    const property = properties.find((p) => p.id === id);
    if (!property) return;
    setForm((current) => ({
      ...current,
      imovelEndereco: property.endereco || "",
      imovelNumero: property.numero || "",
      imovelBairro: property.bairro || "",
      imovelCidade: property.cidade || "Eldorado do Carajás",
      imovelUf: property.uf || "PA",
      imovelCep: property.imovelCep || "",
      imovelComplemento: property.complemento || "",
      matricula: property.matricula,
      ficha: property.ficha,
      livro: property.livro,
      descricaoImovel: property.descricaoImovel,
      areaTotal: property.areaTotal,
      areaConstruida: property.areaConstruida || "",
      unidadeArea: property.unidadeArea,
    }));
  }

  function removeProperty(id: string) {
    persistProperties(properties.filter((property) => property.id !== id));
    setNotice("Imóvel removido.");
  }

  function saveDocument(locked = false) {
    const existingIndex = documents.findIndex((doc) => doc.form.numeroItbi === form.numeroItbi && doc.form.ano === form.ano);
    const record: SavedDocument = {
      id: existingIndex >= 0 ? documents[existingIndex].id : uid(),
      createdAt: existingIndex >= 0 ? documents[existingIndex].createdAt : new Date().toISOString(),
      locked,
      form,
    };
    const next = existingIndex >= 0 ? documents.map((doc, i) => (i === existingIndex ? record : doc)) : [record, ...documents];
    persistDocuments(next);
    setNotice(locked ? "Documento finalizado e salvo no histórico." : "Documento salvo no histórico.");
  }

  function openDocument(id: string) {
    const doc = documents.find((item) => item.id === id);
    if (!doc) return;
    setForm({ ...createEmptyForm(), ...doc.form });
    window.scrollTo({ top: 0, behavior: "smooth" });
    setNotice(doc.locked ? "Documento finalizado carregado. Use Duplicar se precisar alterar." : "Documento carregado.");
  }

  function duplicateDocument(id: string) {
    const doc = documents.find((item) => item.id === id);
    if (!doc) return;
    setForm({ ...createEmptyForm(), ...doc.form, numeroItbi: "", dataEmissao: new Date().toISOString().slice(0, 10) });
    window.scrollTo({ top: 0, behavior: "smooth" });
    setNotice("Documento duplicado. Informe novo número e ajuste os dados necessários.");
  }

  function removeDocument(id: string) {
    persistDocuments(documents.filter((doc) => doc.id !== id));
    setNotice("Documento removido do histórico.");
  }

  function clearForm() {
    setForm(createEmptyForm());
    setNotice("Formulário limpo.");
  }

  function startNewDocument() {
    const base = createEmptyForm();
    const nextNumber = getNextItbiNumber(documents, base.ano);
    setForm({ ...base, numeroItbi: nextNumber });
    window.scrollTo({ top: 0, behavior: "smooth" });
    setNotice(`Novo documento iniciado. Número sugerido: ${nextNumber}/${base.ano}.`);
  }

  function printPdf() {
    saveDocument(true);
    setTimeout(() => window.print(), 100);
  }

  function exportBackup() {
    const payload = {
      version: 7,
      exportedAt: new Date().toISOString(),
      draft: form,
      people,
      properties,
      documents,
    };
    const blob = new Blob([JSON.stringify(payload, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement("a");
    anchor.href = url;
    anchor.download = `backup-itbi-${new Date().toISOString().slice(0, 10)}.json`;
    anchor.click();
    URL.revokeObjectURL(url);
    setNotice("Backup exportado.");
  }

  async function importBackup(file: File) {
    try {
      const text = await file.text();
      const data = JSON.parse(text);
      if (data.draft) setForm({ ...createEmptyForm(), ...data.draft });
      if (Array.isArray(data.people)) persistPeople(data.people);
      if (Array.isArray(data.properties)) persistProperties(data.properties);
      if (Array.isArray(data.documents)) persistDocuments(data.documents);
      setNotice("Backup importado com sucesso.");
    } catch {
      setNotice("Arquivo de backup inválido.");
    }
  }

  const adquirentes = people.filter((p) => p.type === "adquirente");
  const transmitentes = people.filter((p) => p.type === "transmitente");

  return (
    <main className="min-h-screen bg-slate-100 px-6 py-8 text-slate-900 print:bg-white print:px-0 print:py-0">
      <style>{printStyles}</style>
      <div className="mx-auto max-w-7xl print:max-w-none">
        <header className="no-print mb-8 flex flex-col gap-4 rounded-2xl border border-slate-200 bg-white p-6 shadow-sm md:flex-row md:items-center md:justify-between">
          <div>
            <a href="/" className="text-sm font-bold text-emerald-700">← Voltar</a>
            <h1 className="mt-3 text-3xl font-bold tracking-tight">Novo ITBI</h1>
            <p className="mt-2 text-sm text-slate-600">Gerador simples, local e focado apenas no documento final.</p>
          </div>
          <div className="rounded-2xl bg-emerald-50 px-5 py-4 text-right">
            <p className="text-xs font-bold uppercase tracking-wide text-emerald-700">Valor total</p>
            <p className="text-2xl font-black text-emerald-900">{formatCurrency(valores.total)}</p>
          </div>
        </header>

        {notice && <div className="no-print mb-6 rounded-xl border border-emerald-200 bg-emerald-50 px-4 py-3 text-sm font-bold text-emerald-900">{notice}</div>}

        <div className="no-print mb-6 flex justify-end gap-2">
          <TinyButton onClick={exportBackup}>Exportar backup</TinyButton>
          <TinyButton onClick={() => importInputRef.current?.click()}>Importar backup</TinyButton>
          <input ref={importInputRef} type="file" accept="application/json" className="hidden" onChange={(e) => e.target.files?.[0] && importBackup(e.target.files[0])} />
        </div>

        <div className="grid gap-6 lg:grid-cols-[1.15fr_0.85fr] print:block">
          <section className="no-print space-y-6">
            <Card title="Dados do ITBI">
              <div className="grid gap-4 md:grid-cols-3">
                <Input label="Número do ITBI" value={form.numeroItbi} onChange={(v) => updateField("numeroItbi", v)} placeholder="27" />
                <Input label="Ano" value={form.ano} onChange={(v) => updateField("ano", v)} placeholder="2026" />
                <Input label="Data de emissão" type="date" value={form.dataEmissao} onChange={(v) => updateField("dataEmissao", v)} />
              </div>
              <div className="mt-4 grid gap-3 md:grid-cols-2">
                <div className="rounded-xl border border-amber-200 bg-amber-50 px-4 py-3 text-sm text-amber-950">
                  <strong>Último ITBI gerado:</strong> {getLastItbiLabel(documents)}
                </div>
                <div className="rounded-xl border border-emerald-200 bg-emerald-50 px-4 py-3 text-sm text-emerald-950">
                  <strong>Próximo sugerido:</strong> {getNextItbiNumber(documents, form.ano || new Date().getFullYear().toString())}/{form.ano || new Date().getFullYear()}
                </div>
              </div>
            </Card>

            <Card title="01) Dados do adquirente">
              <Selector label="Selecionar adquirente salvo" items={adquirentes} onSelect={(id) => applyPerson(id, "adquirente")} onRemove={removePerson} />
              <div className="mt-4 grid gap-4 md:grid-cols-2">
                <Input label="CPF/CNPJ" value={form.adquirenteCpfCnpj} onChange={(v) => updateField("adquirenteCpfCnpj", v)} />
                <Input label="Nome" value={form.adquirenteNome} onChange={(v) => updateField("adquirenteNome", v)} />
                <Input label="Logradouro" value={form.adquirenteEndereco} onChange={(v) => updateField("adquirenteEndereco", v)} />
                <Input label="Nº" value={form.adquirenteNumero} onChange={(v) => updateField("adquirenteNumero", v)} />
                <Input label="Complemento" value={form.adquirenteComplemento} onChange={(v) => updateField("adquirenteComplemento", v)} />
                <Input label="CEP" value={form.adquirenteCep} onChange={(v) => updateField("adquirenteCep", v)} />
                <Input label="Bairro" value={form.adquirenteBairro} onChange={(v) => updateField("adquirenteBairro", v)} />
                <Input label="Cidade" value={form.adquirenteCidade} onChange={(v) => updateField("adquirenteCidade", v)} />
                <Input label="UF" value={form.adquirenteUf} onChange={(v) => updateField("adquirenteUf", v.toUpperCase().slice(0, 2))} />
              </div>
              <button onClick={() => saveCurrentPerson("adquirente")} className="mt-4 rounded-xl bg-slate-900 px-4 py-2 text-xs font-black text-white">Salvar adquirente</button>
            </Card>

            <Card title="02) Dados do(s) transmitente(s)">
              <Selector label="Selecionar transmitente salvo" items={transmitentes} onSelect={(id) => applyPerson(id, "transmitente")} onRemove={removePerson} />
              <div className="mt-4 grid gap-4 md:grid-cols-2">
                <Input label="CPF/CNPJ" value={form.transmitenteCpfCnpj} onChange={(v) => updateField("transmitenteCpfCnpj", v)} />
                <Input label="Nome" value={form.transmitenteNome} onChange={(v) => updateField("transmitenteNome", v)} />
                <Input label="Logradouro" value={form.transmitenteEndereco} onChange={(v) => updateField("transmitenteEndereco", v)} />
                <Input label="Nº" value={form.transmitenteNumero} onChange={(v) => updateField("transmitenteNumero", v)} />
                <Input label="Complemento" value={form.transmitenteComplemento} onChange={(v) => updateField("transmitenteComplemento", v)} />
                <Input label="CEP" value={form.transmitenteCep} onChange={(v) => updateField("transmitenteCep", v)} />
                <Input label="Bairro" value={form.transmitenteBairro} onChange={(v) => updateField("transmitenteBairro", v)} />
                <Input label="Cidade" value={form.transmitenteCidade} onChange={(v) => updateField("transmitenteCidade", v)} />
                <Input label="UF" value={form.transmitenteUf} onChange={(v) => updateField("transmitenteUf", v.toUpperCase().slice(0, 2))} />
              </div>
              <button onClick={() => saveCurrentPerson("transmitente")} className="mt-4 rounded-xl bg-slate-900 px-4 py-2 text-xs font-black text-white">Salvar transmitente</button>
            </Card>

            <Card title="03) Dados da transmissão">
              <div className="grid gap-4 md:grid-cols-3">
                <Input label="Tipo de transmissão" value={form.tipoTransmissao} onChange={(v) => updateField("tipoTransmissao", v)} />
                <Input label="Alíquota (%)" value={form.aliquota} onChange={(v) => updateField("aliquota", v)} />
                <Input label="Valor da avaliação venal" value={form.valorVenal} onChange={(v) => updateField("valorVenal", v)} onBlur={() => formatMoneyField("valorVenal")} />
                <Input label="Valor financiado" value={form.valorFinanciado} onChange={(v) => updateField("valorFinanciado", v)} onBlur={() => formatMoneyField("valorFinanciado")} />
              </div>
            </Card>

            <Card title="04) Dados do imóvel">
              <Selector label="Selecionar imóvel salvo" items={properties.map((p) => ({ id: p.id, nome: p.nome, cpfCnpj: p.descricaoImovel, type: "adquirente" as const, endereco: "", bairro: "", cep: "" }))} onSelect={applyProperty} onRemove={removeProperty} />
              <div className="mt-4 grid gap-4 md:grid-cols-3">
                <Input label="Logradouro" value={form.imovelEndereco} onChange={(v) => updateField("imovelEndereco", v)} />
                <Input label="Nº" value={form.imovelNumero} onChange={(v) => updateField("imovelNumero", v)} />
                <Input label="Bairro" value={form.imovelBairro} onChange={(v) => updateField("imovelBairro", v)} />
                <Input label="Cidade" value={form.imovelCidade} onChange={(v) => updateField("imovelCidade", v)} />
                <Input label="UF" value={form.imovelUf} onChange={(v) => updateField("imovelUf", v.toUpperCase().slice(0, 2))} />
                <Input label="CEP" value={form.imovelCep} onChange={(v) => updateField("imovelCep", v)} />
                <Input label="Complemento" value={form.imovelComplemento} onChange={(v) => updateField("imovelComplemento", v)} />
                <Input label="Matrícula" value={form.matricula} onChange={(v) => updateField("matricula", v)} />
                <Input label="Ficha" value={form.ficha} onChange={(v) => updateField("ficha", v)} />
                <Input label="Livro" value={form.livro} onChange={(v) => updateField("livro", v)} />
                <Input label="Área total" value={form.areaTotal} onChange={(v) => updateField("areaTotal", v)} />
                <Input label="Área construída" value={form.areaConstruida} onChange={(v) => updateField("areaConstruida", v)} />
                <Input label="Unidade" value={form.unidadeArea} onChange={(v) => updateField("unidadeArea", v)} />
                <div className="md:col-span-3">
                  <label className="mb-2 block text-sm font-bold text-slate-700">Descrição do imóvel</label>
                  <textarea value={form.descricaoImovel} onChange={(e) => updateField("descricaoImovel", e.target.value)} className="min-h-28 w-full rounded-xl border border-slate-300 bg-white px-4 py-3 text-sm outline-none focus:border-emerald-600 focus:ring-4 focus:ring-emerald-100" />
                </div>
              </div>
              <button onClick={saveCurrentProperty} className="mt-4 rounded-xl bg-slate-900 px-4 py-2 text-xs font-black text-white">Salvar imóvel</button>
            </Card>

            <Card title="Observações e assinatura">
              <div className="grid gap-4 md:grid-cols-3">
                <Input label="Responsável" value={form.responsavelNome} onChange={(v) => updateField("responsavelNome", v)} />
                <Input label="Cargo" value={form.responsavelCargo} onChange={(v) => updateField("responsavelCargo", v)} />
                <Input label="Portaria" value={form.responsavelPortaria} onChange={(v) => updateField("responsavelPortaria", v)} />
                <div className="md:col-span-3">
                  <label className="mb-2 block text-sm font-bold text-slate-700">Observações complementares</label>
                  <textarea value={form.observacoes} onChange={(e) => updateField("observacoes", e.target.value)} className="min-h-20 w-full rounded-xl border border-slate-300 bg-white px-4 py-3 text-sm outline-none focus:border-emerald-600 focus:ring-4 focus:ring-emerald-100" />
                </div>
              </div>
              <div className="mt-6 flex flex-col gap-3 rounded-2xl border border-emerald-200 bg-emerald-50 p-4 md:flex-row md:items-center md:justify-between">
                <div>
                  <p className="text-sm font-black text-emerald-950">Final do preenchimento</p>
                  <p className="text-xs text-emerald-800">Salve no histórico quando terminar de conferir os dados.</p>
                </div>
                <button onClick={() => saveDocument(false)} className="rounded-xl bg-emerald-700 px-5 py-3 text-sm font-black text-white hover:bg-emerald-800">Salvar no histórico</button>
              </div>
            </Card>
          </section>

          <aside className="no-print lg:sticky lg:top-8 lg:self-start">
            <div className="rounded-2xl border border-slate-200 bg-white p-6 shadow-sm">
              <h2 className="text-xl font-black">Conferência</h2>
              <p className="mt-1 text-sm text-slate-600">Campos essenciais: {essentialStatus.filled}/{essentialStatus.total}</p>
              <div className="mt-4 space-y-2 text-sm">
                {essentialStatus.items.map(([label, value]) => <PreviewRow key={label} label={label} value={String(value).trim() ? "OK" : "Pendente"} />)}
              </div>
              <div className="mt-5 border-t pt-4 text-sm">
                <PreviewRow label="Base de cálculo" value={formatCurrency(valores.baseCalculo)} />
                <PreviewRow label="Imposto" value={formatCurrency(valores.imposto)} />
                <PreviewRow label="Valor total" value={formatCurrency(valores.total)} strong />
              </div>
              <button onClick={printPdf} className="mt-6 w-full rounded-xl bg-emerald-700 px-5 py-3 text-sm font-black text-white hover:bg-emerald-800">Gerar PDF oficial / imprimir</button>
              <button onClick={startNewDocument} className="mt-3 w-full rounded-xl bg-slate-900 px-5 py-3 text-sm font-black text-white hover:bg-slate-800">Novo documento</button>
              <button onClick={clearForm} className="mt-3 w-full rounded-xl bg-slate-100 px-5 py-3 text-sm font-black text-slate-700 hover:bg-slate-200">Limpar sem sugerir número</button>
            </div>
          </aside>
        </div>

        <DocumentPreview form={form} valores={valores} />

        <section className="no-print mt-8 rounded-2xl border border-slate-200 bg-white p-6 shadow-sm">
          <h2 className="text-xl font-black">Histórico local</h2>
          <div className="mt-4 space-y-3">
            {documents.length === 0 && <p className="text-sm text-slate-500">Nenhum documento salvo ainda.</p>}
            {documents.map((doc) => (
              <div key={doc.id} className="flex flex-col gap-3 rounded-xl border border-slate-200 p-4 md:flex-row md:items-center md:justify-between">
                <div>
                  <p className="font-black">ITBI {doc.form.numeroItbi || "sem número"}/{doc.form.ano} {doc.locked ? "• FINALIZADO" : "• RASCUNHO"}</p>
                  <p className="text-sm text-slate-600">{doc.form.adquirenteNome || "Adquirente não informado"}</p>
                  <p className="text-xs text-slate-500">{new Date(doc.createdAt).toLocaleString("pt-BR")}</p>
                </div>
                <div className="flex flex-wrap gap-2">
                  <SmallButton onClick={() => openDocument(doc.id)}>Abrir</SmallButton>
                  <SmallButton onClick={() => duplicateDocument(doc.id)}>Duplicar</SmallButton>
                  <SmallButton onClick={() => removeDocument(doc.id)}>Remover</SmallButton>
                </div>
              </div>
            ))}
          </div>
        </section>
      </div>
    </main>
  );
}

